using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a realistic corpus by repeating a paragraph many times.
        const string paragraph =
            "The quick brown fox jumps over the lazy dog and then the fox "
          + "decided to rest under a large oak tree while the dog watched "
          + "from across the wide green meadow near the flowing river bank";
        _analyzer = new TextAnalyzer(string.Join(' ', Enumerable.Repeat(paragraph, 200)));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

